const sys = Buffer.from($('Load System').first().json.content, 'base64').toString('utf-8');
const usrTemplate = Buffer.from($('Load User').first().json.content, 'base64').toString('utf-8');

return $input.all().map(item => {
  const inp = item.json;
  let usr = usrTemplate;
  const vars = {
    course_id: inp.course_id||'',
    chapter_index: inp.chapter_index||0,
    chunk_index: inp.chunk_index||1,
    source_language: inp.source_language||'fr',
    target_language: inp.target_language||'en-US',
    detected_domain: inp.detected_domain||'',
    html_content: inp.html||inp.html_content||'',
    source_html: inp.html||inp.source_html||'',
    pretranslation_draft: inp.pretranslation_draft||'',
    translated_html: inp.translated_html||'',
    preceding_context: inp.preceding_context||'',
    a1_audit: JSON.stringify(inp.a1_audit||{}),
    a1_outputs: JSON.stringify(inp.a1_outputs||[]),
    a2_glossary: JSON.stringify(inp.a2_glossary||{}),
    a4_swap_log: JSON.stringify(inp.a4_swap_log||[]),
    common_glossary: JSON.stringify(inp.common_glossary||[]),
    domain_validated_tm: JSON.stringify(inp.domain_validated_tm||[]),
    domain_unvalidated_tm: JSON.stringify(inp.domain_unvalidated_tm||[]),
    iteration: inp.iteration||1,
    failing_segments: JSON.stringify(inp.failing_segments||[]),
    previous_qa_report: JSON.stringify(inp.previous_qa_report||{}),
    score_target: inp.score_target||90
  };
  Object.entries(vars).forEach(([k,v]) => {
    usr = usr.replace(new RegExp('\\{{'+k+'\\}}','g'), String(v));
  });
  return {json:{
    system_prompt: sys,
    user_message: usr,
    model: 'gpt-5.2',
    temperature: 0.1,
    max_tokens: 16000,
    custom_id: (inp.course_id||'x')+'-ch'+(inp.chapter_index||0)+'-ck'+(inp.chunk_index||1)+'-a1sourceanalyst',
    agent_name: 'A1 Source Analyst',
    course_id: inp.course_id,
    chapter_index: inp.chapter_index,
    chunk_index: inp.chunk_index,
    pipeline_meta: inp.pipeline_meta||{}
  }};
});

const p = $input.first().json;
const results = p.results || [{custom_id: p.custom_id, parsed_content: p.agent_output, finish_reason:'stop'}];
return results.map(r => {
  const parts = (r.custom_id||'').split('-');
  const chStr = parts.find(s=>s.startsWith('ch'))||'ch0';
  const ckStr = parts.find(s=>s.startsWith('ck'))||'ck1';
  const chapter_index = parseInt(chStr.replace('ch',''))||0;
  const chunk_index   = parseInt(ckStr.replace('ck',''))||1;
  return {json:{
    status: r.parsed_content ? 'ok' : 'error',
    agent: 'A1 Source Analyst',
    agent_output: r.parsed_content || null,
    course_id: p.course_id, chapter_index, chunk_index,
    pipeline_meta: p.pipeline_meta||{}
  }};
});

